// Condensed system prompt. The full authoritative version lives in
// bp-specialized-team/prompts/malak-admin-pa.md — keep the two in sync.
const tasks = $input.all()
  .map(i => i.json)
  .filter(j => j && (j.name || j.properties))
  .slice(0, 100);
const tasksText = tasks.length
  ? JSON.stringify(tasks)
  : 'TASKS_UNAVAILABLE — produce a brief noting the Tasks DB could not be read.';

const systemPrompt = [
  'You are Malak, the internal Admin Manager & Personal Assistant Agent for Business Partner (بزنس بارتنر سلوشنز).',
  'Build the daily brief for Baher and the team from the tasks JSON provided.',
  'Rules:',
  '- Write in Arabic, short and decision-oriented.',
  '- Order: 1) overdue and urgent tasks (owner + due date), 2) today\'s tasks and appointments, 3) reminders for the next 7 days, 4) notes/collated outputs.',
  '- Never include OTP, verification codes, passwords, or credentials — if a task mentions them, mark it "Human Required" and do not process it.',
  '- Never draft outward/client messages as sent — anything outward is a draft pending approval.',
  '- Do not invent tasks or dates; only use what is in the data.',
  '',
  'Tasks (JSON):',
  tasksText
].join('\n');

return [{
  json: {
    anthropic_body: {
      model: 'claude-sonnet-5',
      max_tokens: 1500,
      system: systemPrompt,
      messages: [{ role: 'user', content: 'جهز الملخص اليومي الآن.' }]
    },
    task_count: tasks.length
  }
}];

// Resilience (Compliance Agent V1 pattern): if the engine fails, write a structured
// fallback brief so the daily record always exists.
const item = $input.first().json;
const meta = $('Build Claude Request').first().json;

let text = '';
if (item && Array.isArray(item.content) && item.content[0] && item.content[0].text) {
  text = item.content[0].text;
}
const engine_fallback = !text;
if (engine_fallback) {
  text = 'ملخص احتياطي (تعذر توليد Claude):\n' +
    'عدد المهام المقروءة من نوشن: ' + (meta.task_count ?? 0) + '.\n' +
    'يرجى مراجعة قاعدة المهام مباشرة اليوم. سيعود التلخيص الذكي عند توفر المحرك.';
}

return [{ json: { brief: text, engine_fallback, task_count: meta.task_count ?? 0 } }];
